import type Accessor from "../../core/Accessor.js";

/** @deprecated since version 5.0. Use the [Building Explorer component](https://developers.arcgis.com/javascript/latest/references/map-components/components/arcgis-building-explorer/) instead. For information on widget deprecation, read about [Esri's move to web components](https://developers.arcgis.com/javascript/latest/components-transition-plan/). */
export interface BuildingNumericFilterViewModelProperties extends Partial<Pick<BuildingNumericFilterViewModel, "enabled" | "value">> {
  /** List of all the values which are allowed for the filter. */
  allowedValues?: readonly number[] | null;
}

/**
 * Base class for the level filter and the construction phase filter in the
 * [BuildingExplorerViewModel](https://developers.arcgis.com/javascript/latest/references/core/widgets/BuildingExplorer/BuildingExplorerViewModel/).
 *
 * @deprecated since version 5.0. Use the [Building Explorer component](https://developers.arcgis.com/javascript/latest/references/map-components/components/arcgis-building-explorer/) instead. For information on widget deprecation, read about [Esri's move to web components](https://developers.arcgis.com/javascript/latest/components-transition-plan/).
 * @since 4.16
 */
export default abstract class BuildingNumericFilterViewModel extends Accessor {
  /** List of all the values which are allowed for the filter. */
  get allowedValues(): readonly number[];
  set allowedValues(value: readonly number[] | null | undefined);
  /**
   * Whether the filter is enabled. If false, the filter's expression won't be
   * used to filter a [BuildingSceneLayer](https://developers.arcgis.com/javascript/latest/references/core/layers/BuildingSceneLayer/).
   *
   * @default false
   */
  accessor enabled: boolean;
  /** Whether the next value can be selected. */
  get hasNext(): boolean;
  /** Whether the previous value can be selected. */
  get hasPrevious(): boolean;
  /** The maximum value allowed for the filter. */
  get max(): number | null | undefined;
  /** The minimum value allowed for the filter. */
  get min(): number | null | undefined;
  /** The value which is currently set on the filter. */
  accessor value: number;
  /** Removes the filter by setting [enabled](https://developers.arcgis.com/javascript/latest/references/core/widgets/BuildingExplorer/BuildingNumericFilterViewModel/#enabled) to `false`. */
  clear(): void;
  /**
   * If the field that is used for filtering has a coded value domain, the label for the value can
   * be used to be displayed in a tooltip or in the widget UI. This method returns the label
   * corresponding to a certain value.
   *
   * @param value - A filter value.
   * @returns The label corresponding to the filter value.
   */
  getValueLabel(value: number): string | null | undefined;
  /**
   * Selects the next value, if available. If [enabled](https://developers.arcgis.com/javascript/latest/references/core/widgets/BuildingExplorer/BuildingNumericFilterViewModel/#enabled) is `false`,
   * the first allowed value is selected.
   */
  next(): void;
  /**
   * Selects the previous value, if available. If [enabled](https://developers.arcgis.com/javascript/latest/references/core/widgets/BuildingExplorer/BuildingNumericFilterViewModel/#enabled) is `false`,
   * the last allowed value is selected.
   */
  previous(): void;
  /**
   * Selects the specified value for the filter. In case the filter is disabled, this
   * method also enables it by setting [enabled](https://developers.arcgis.com/javascript/latest/references/core/widgets/BuildingExplorer/BuildingNumericFilterViewModel/#enabled) to `true`.
   *
   * @param value - The value which is to be selected.
   */
  select(value: number): void;
}